Greedy-insert each order into the assign whose current route after insertion yields the smallest positive marginal cost increase per unit distance saved, with tie-breaking toward fewer stations, using a fallback to the first empty/new assign if all existing routes reject the order.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx       int
		delta     float64
		score     float64
		stationCnt int
	}
	const INF = 1e18
	nAssigns := dispatch.AssignsLen
	if nAssigns == 0 {
		nAssigns = 1
	}
	for oIdx, ori := range oris {
		des := dess[oIdx]
		shipID := total_ship + oIdx
		baseDist := cal_dis(ori, des)
		bestCandidate := candidate{-1, INF, INF, 0}
		emptySlot := -1
		for ai := 0; ai < nAssigns; ai++ {
			a := &dispatch.Assigns[ai]
			if a.StationsLen == 0 {
				if emptySlot == -1 {
					emptySlot = ai
				}
				continue
			}
			oldCost := a.Cost
			ok := a.AddShip(shipID, ori, des)
			if !ok {
				continue
			}
			a.GenRoute()
			if a.Cost < 0 || a.Cost < oldCost-1e-9 {
				a.RemoveShip(shipID)
				a.GenRoute()
				continue
			}
			delta := a.Cost - oldCost
			score := delta / (baseDist + 1e-6)
			if score < bestCandidate.score ||
			   (score == bestCandidate.score && a.StationsLen < bestCandidate.stationCnt) {
				bestCandidate.idx = ai
				bestCandidate.delta = delta
				bestCandidate.score = score
				bestCandidate.stationCnt = a.StationsLen
			}
			a.RemoveShip(shipID)
			a.GenRoute()
		}
		newCandidateIdx := -1
		if dispatch.AssignsLen < MAXASSIGNS {
			newCandidateIdx = dispatch.AssignsLen
		}
		inserted := false
		if bestCandidate.idx != -1 {
			target := &dispatch.Assigns[bestCandidate.idx]
			target.AddShip(shipID, ori, des)
			target.GenRoute()
			inserted = true
		} else if emptySlot != -1 {
			target := &dispatch.Assigns[emptySlot]
			target.AddShip(shipID, ori, des)
			target.GenRoute()
			inserted = true
			if emptySlot >= dispatch.AssignsLen {
				dispatch.AssignsLen = emptySlot + 1
			}
		} else if newCandidateIdx != -1 {
			target := &dispatch.Assigns[newCandidateIdx]
			target.AddShip(shipID, ori, des)
			target.GenRoute()
			inserted = true
			if newCandidateIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen = newCandidateIdx + 1
			}
		}
		if !inserted {
			fallbackIdx := -1
			for i := 0; i < MAXASSIGNS; i++ {
				if dispatch.Assigns[i].StationsLen == 0 {
					fallbackIdx = i
					break
				}
			}
			if fallbackIdx == -1 && dispatch.AssignsLen < MAXASSIGNS {
				fallbackIdx = dispatch.AssignsLen
			}
			if fallbackIdx != -1 {
				target := &dispatch.Assigns[fallbackIdx]
				target.AddShip(shipID, ori, des)
				target.GenRoute()
				if target.Cost >= 0 {
					inserted = true
					if fallbackIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen = fallbackIdx + 1
					}
				} else {
					target.RemoveShip(shipID)
					target.GenRoute()
				}
			}
		}
		nAssigns = dispatch.AssignsLen
		if nAssigns == 0 {
			nAssigns = 1
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

